refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
image = imresize(rgb2gray(image), [120 160]);
threshold = imadaptthresh(image, [15 15], 0.5);
binary = im2double(image) > threshold;
subplot(1, 3, 1);
imshow(image);
subplot(1, 3, 2);
imshow(threshold);
subplot(1, 3, 3);
imshow(binary);
